"use strict";(self.webpackChunkchatgpt_shortcut=self.webpackChunkchatgpt_shortcut||[]).push([["9385"],{41228(a,n,e){e.r(n),e.d(n,{default:()=>r});var i=e(74848),t=e(47643),s=JSON.parse('{"id":95,"ind":{"title":"Arsitek TI","prompt":"I want you to act as an IT Architect. I will provide some details about the functionality of an application or other digital product, and it will be your job to come up with ways to integrate it into the IT landscape. This could involve analyzing business requirements, performing a gap analysis and mapping the functionality of the new system to the existing IT landscape. Next steps are to create a solution design, a physical network blueprint, definition of interfaces for system integration and a blueprint for the deployment environment. Respond in Indonesian. My first request is [detail fungsionalitas aplikasi]","description":"Saya ingin Anda bertindak sebagai Arsitek TI. Saya akan memberikan beberapa detail tentang fungsionalitas aplikasi atau produk digital lainnya, dan tugas Anda adalah memikirkan cara untuk mengintegrasikannya ke dalam lanskap TI. Ini bisa melibatkan analisis persyaratan bisnis, melakukan analisis kesenjangan, dan memetakan fungsionalitas sistem baru ke lanskap TI yang ada. Langkah selanjutnya adalah membuat desain solusi, cetak biru jaringan fisik, definisi antarmuka untuk integrasi sistem, dan cetak biru untuk lingkungan penyebaran.","remark":"Merancang solusi sistem dari perspektif arsitek TI."},"tags":["code"],"website":"https://github.com/f/awesome-chatgpt-prompts#act-as-an-it-architect","count":3289,"related":[{"id":90,"title":"Jawaban StackOverflow","remark":"Simulasikan komunitas pemrograman untuk menjawab pertanyaan Anda dan memberikan kode solusi."},{"id":218,"title":"Code Anything Now (CAN)","remark":"Biarkan ChatGPT mengajukan pertanyaan proaktif untuk memandu manusia dalam penulisan kode langkah demi langkah. Dikumpulkan dari Snackprompt, dibagikan oleh @fuxinsen."},{"id":173,"title":"Penerjemah Kode","remark":"Biarkan AI menjelaskan fungsi dari setiap baris kode. Dikontribusikan oleh @Tractor1928 dan @yiqiongwu."}],"metaTitle":"Follow-up Email: Tindak Lanjut Pelanggan","metaDescription":"Menindaklanjuti pelanggan? Tulis email follow-up yang sopan dan efektif!","faq":[{"q":"Seberapa bisa dipercaya rencana arsitektur enterprise?","a":"Arah kerangka besar seperti mikroservis, event driven, DDD deskripsinya akurat. Pemilihan teknologi spesifik harus dipadukan dengan tech debt dan kapabilitas tim. AI tidak tahu apakah timmu familiar dengan Kubernetes. Rencana yang direkomendasikannya bisa butuh 6 bulan hanya untuk menguasai."},{"q":"Apakah kebutuhan non-fungsional seperti compliance atau security sudah dipertimbangkan AI?","a":"Default tidak mendalam. Kalau menyangkut keuangan, medis, atau data pribadi, sebutkan jelas \'rencana harus memenuhi GDPR, MLPS Level 3, HIPAA\'. AI akan menambahkan modul terkait seperti audit log, enkripsi data, isolasi akses. Tanpa menyebut, AI default kasih rencana umum, detail compliance hampir semua terlewat."}],"datePublished":"2026-05-27T01:46:29+00:00","dateModified":"2026-05-27T02:40:13+00:00"}');function r(){return(0,i.jsx)(t.A,{prompt:s,currentLanguage:"ind"})}}}]);